onClick:
{{
  (() => {

    const norm = s =>
      (s || "")
        .trim()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .toLowerCase();

    const newName = inpPLRenameName.text;
    const oldId = tblPicklistItems.selectedRow.id;

    const exists = getPicklistItems.data.some(
      item =>
        item.id !== oldId &&
        item.name &&
        norm(item.name) === norm(newName)
    );

    if (exists) {
      showAlert('Name already exists in this list', 'warning');
    } else {
      renamePicklistItem.run()
        .then(() => getPicklistItems.run())
        .then(() => closeModal('mdlPLRename'))
        .then(() => showAlert('Item renamed', 'success'));
    }

  })()
}}
